    "inlineSchema": "generator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel LearningSlide {\n  id         String   @id\n  moduleId   String\n  title      String\n  layoutType String\n  imageUrl   String?\n  bullets    String[]\n  orderIndex Int\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime\n  Module     Module   @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n}\n\nmodel Module {\n  id                 String               @id\n  slug               String               @unique\n  name               String\n  description        String\n  tier               String\n  xpPoints           Int\n  orderIndex         Int\n  createdAt          DateTime             @default(now())\n  updatedAt          DateTime\n  topicId            String?\n  level              ModuleLevel?\n  LearningSlide      LearningSlide[]\n  Topic              Topic?               @relation(fields: [topicId], references: [id])\n  QuizAttempt        QuizAttempt[]\n  QuizQuestion       QuizQuestion[]\n  UserModuleProgress UserModuleProgress[]\n\n  @@index([topicId, level])\n}\n\nmodel QuizAttempt {\n  id                String              @id\n  userId            String\n  moduleId          String\n  totalQuestions    Int\n  correctAnswers    Int\n  percentage        Float\n  xpEarned          Int\n  attemptedAt       DateTime            @default(now())\n  Module            Module              @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  User              User                @relation(fields: [userId], references: [id], onDelete: Cascade)\n  QuizAttemptAnswer QuizAttemptAnswer[]\n}\n\nmodel QuizAttemptAnswer {\n  id             String       @id\n  attemptId      String\n  questionId     String\n  selectedAnswer String\n  isCorrect      Boolean\n  QuizAttempt    QuizAttempt  @relation(fields: [attemptId], references: [id], onDelete: Cascade)\n  QuizQuestion   QuizQuestion @relation(fields: [questionId], references: [id], onDelete: Cascade)\n}\n\nmodel QuizQuestion {\n  id                String              @id\n  moduleId          String\n  question          String\n  optionA           String\n  optionB           String\n  optionC           String\n  optionD           String\n  correctAnswer     String\n  explanation       String\n  orderIndex        Int\n  createdAt         DateTime            @default(now())\n  updatedAt         DateTime\n  QuizAttemptAnswer QuizAttemptAnswer[]\n  Module            Module              @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n}\n\nmodel Topic {\n  id          String     @id\n  name        String     @unique\n  description String     @default(\"\")\n  orderIndex  Int        @unique\n  createdAt   DateTime   @default(now())\n  updatedAt   DateTime\n  slug        String     @unique\n  theme       TopicTheme @default(TECH)\n  Module      Module[]\n}\n\nmodel User {\n  id                 String               @id\n  name               String\n  email              String               @unique\n  passwordHash       String\n  role               Role                 @default(ENTHUSIAST)\n  xp                 Int                  @default(0)\n  createdAt          DateTime             @default(now())\n  updatedAt          DateTime\n  eventxp            Int                  @default(0)\n  QuizAttempt        QuizAttempt[]\n  UserModuleProgress UserModuleProgress[]\n}\n\nmodel UserModuleProgress {\n  id          String         @id\n  userId      String\n  moduleId    String\n  status      ProgressStatus @default(LOCKED)\n  score       Int?\n  xpEarned    Int            @default(0)\n  completedAt DateTime?\n  createdAt   DateTime       @default(now())\n  updatedAt   DateTime\n  Module      Module         @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  User        User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, moduleId])\n}\n\nenum ModuleLevel {\n  BEGINNER\n  INTERMEDIATE\n  ADVANCED\n}\n\nenum ProgressStatus {\n  LOCKED\n  UNLOCKED\n  COMPLETED\n}\n\nenum Role {\n  CORE\n  CREW\n  ENTHUSIAST\n}\n\nenum TopicTheme {\n  TECH\n  FORGE\n  CITADEL\n  HARBOR\n  CRYSTAL\n}\n",
